const state={files:[],folder:"",libraryRoot:"LifeLibrary Files",query:"",selected:null,contextTarget:null,clickTimer:null,analysisInFlight:new Set(),settings:null,theme:"purple",categoryFocus:null,connectionFilter:"all",universeSelection:null,universeView:{x:0,y:0,scale:1},universePan:null,universeDidPan:false,thumbnailCache:new Map(),thumbnailLoading:new Set(),summaryArtFolders:new Set(),batchAnalyzing:false,recentMode:"edited",dashboardQuery:""};
const $=(selector)=>document.querySelector(selector);
const els={tree:$("#folder-tree"),list:$("#file-list"),empty:$("#empty"),allCount:$("#all-count"),title:$("#folder-title"),subtitle:$("#folder-subtitle"),path:$("#current-path"),search:$("#search"),refresh:$("#refresh"),count:$("#item-count"),previewPane:$(".preview-pane"),previewEmpty:$("#preview-empty"),previewContent:$("#preview-content")};
const esc=(value)=>String(value).replace(/[&<>'"]/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"})[c]);
const bytes=(n)=>n<1024?`${n} B`:n<1048576?`${(n/1024).toFixed(1)} KB`:`${(n/1048576).toFixed(1)} MB`;
const parentOf=(file)=>file.relativePath.includes("\\")?file.relativePath.slice(0,file.relativePath.lastIndexOf("\\")):"";
const iconClass=(extension)=>extension===".pdf"?"pdf":[".png",".jpg",".jpeg"].includes(extension)?"image":[".docx",".xlsx",".pptx"].includes(extension)?"office":extension===".mp4"?"media":[".csv",".json",".txt",".md"].includes(extension)?"data":extension===".zip"?"archive":"";
const categoryTrail=(file)=>file.subcategory&&file.subcategory.toLowerCase()!==file.category.toLowerCase()?`${file.category} › ${file.subcategory}`:file.category;
const imageExtensions=new Set([".png",".jpg",".jpeg"]);
const stableHash=(value)=>[...String(value)].reduce((hash,character)=>((hash<<5)-hash+character.charCodeAt(0))|0,0);
const explorerCategoryPalette=[
  {ink:"#6246b7",dot:"#7b61d9",soft:"#eee9ff",border:"#d8cdf8"},
  {ink:"#246f99",dot:"#3d8eb8",soft:"#e4f3fb",border:"#c5e3f2"},
  {ink:"#2f7950",dot:"#4b9a6a",soft:"#e5f4eb",border:"#c8e6d3"},
  {ink:"#9a5d20",dot:"#d08a43",soft:"#fff0df",border:"#f2d6b5"},
  {ink:"#9c4163",dot:"#bf5d7d",soft:"#fae8ef",border:"#edcad7"},
  {ink:"#586179",dot:"#7d8298",soft:"#eceef4",border:"#d5d8e3"},
  {ink:"#7f4b94",dot:"#a06bb8",soft:"#f3e8f8",border:"#e3cbed"},
  {ink:"#347a77",dot:"#5c9d9a",soft:"#e4f3f2",border:"#c5e2e0"}
];
function applyExplorerCategoryColors(){document.querySelectorAll("#file-list .file-row[data-file]").forEach(row=>{const file=state.files.find(item=>item.relativePath===row.dataset.file);const badge=row.querySelector(".pill");if(!file||!badge)return;const palette=explorerCategoryPalette[Math.abs(stableHash(file.category||"Uncategorized"))%explorerCategoryPalette.length];badge.style.setProperty("--category-ink",palette.ink);badge.style.setProperty("--category-dot",palette.dot);badge.style.setProperty("--category-soft",palette.soft);badge.style.setProperty("--category-border",palette.border);if(!badge.querySelector(".pill-label")){const label=document.createElement("span");label.className="pill-label";const category=document.createElement("strong");category.textContent=file.category||"Uncategorized";label.append(category);if(file.subcategory&&file.subcategory.toLowerCase()!==(file.category||"").toLowerCase()){const subcategory=document.createElement("small");subcategory.textContent=file.subcategory;label.append(subcategory);}badge.replaceChildren(label);}});}
const explorerCategoryObserver=new MutationObserver(applyExplorerCategoryColors);
explorerCategoryObserver.observe(els.list,{childList:true});
function documentVisualSpec(file){if(file.visual?.primaryMotif)return file.visual;const value=`${file.name} ${file.category} ${file.subcategory||""} ${file.summary||""}`.toLowerCase();const rules=[[/lab report|experiment/,"Lab Report","flask",["line-chart","table","formula"],"teal"],[/microscopy|microscope/,"Microscopy","microscope",["line-chart","table"],"teal"],[/budget|finance|invoice/,"Budget","calculator",["bar-chart","table"],"green"],[/contract|agreement|legal/,"Agreement","contract",["document","table"],"blue"],[/algorithm|code|computer/,"Algorithm","code",["data-grid","line-chart"],"purple"],[/travel|flight|hotel/,"Travel Plan","plane",["calendar","table"],"orange"],[/syllabus|course|lecture/,"Course","book",["calendar","table"],"blue"],[/presentation|slides/,"Presentation","presentation",["bar-chart","document"],"purple"],[/video|clipchamp/,"Video","video",["calendar"],"red"],[/research|science|physics|biology/,"Research","document",["line-chart","formula","table"],"teal"]];const match=rules.find(([pattern])=>pattern.test(value));if(match)return {label:match[1],primaryMotif:match[2],secondaryMotifs:match[3],accent:match[4]};return {label:(file.subcategory||file.category||"Document").slice(0,20),primaryMotif:"document",secondaryMotifs:["table"],accent:"blue"};}
function motifMarkup(name,x,y,scale,accent){const common=`stroke="#0b3a68" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"`;const drawings={
  flask:`<path d="M9 2h10M11 2v7L5 21c-1 2 0 4 3 4h12c3 0 4-2 3-4L17 9V2" fill="none" ${common}/><path d="M8 19c4 2 9-2 12 0l2 4H6z" fill="${accent}" opacity=".9"/><circle cx="14" cy="14" r="1.5" fill="${accent}"/>`,
  "line-chart":`<path d="M3 3v21h27" fill="none" ${common}/><path d="M5 21c5-8 9-11 14-13s7-2 11-4" fill="none" stroke="${accent}" stroke-width="3" stroke-linecap="round"/><path d="M10 4v17M18 4v17M26 4v17M4 9h25M4 15h25" stroke="#b8c8d5" stroke-width="1" stroke-dasharray="2 2"/>`,
  "bar-chart":`<path d="M3 3v22h28" fill="none" ${common}/><rect x="7" y="14" width="5" height="10" rx="1" fill="${accent}"/><rect x="16" y="8" width="5" height="16" rx="1" fill="${accent}" opacity=".75"/><rect x="25" y="4" width="5" height="20" rx="1" fill="${accent}" opacity=".5"/>`,
  table:`<rect x="2" y="3" width="30" height="23" rx="2" fill="#f7fbfd" ${common}/><path d="M2 10h30M12 3v23M22 3v23M2 18h30" stroke="#8da6b8" stroke-width="1.4"/><path d="M3 4h28v6H3z" fill="${accent}" opacity=".35"/>`,
  formula:`<rect x="1" y="5" width="32" height="20" rx="4" fill="#eef5f8"/><text x="17" y="19" text-anchor="middle" font-family="Georgia,serif" font-style="italic" font-size="11" fill="#0b3a68">ƒ(x)</text>`,
  microscope:`<path d="M12 3l7 7-4 4-7-7zM9 14c-4 6 0 10 7 10M6 26h21M18 14l5 5M20 19h7" fill="none" ${common}/><circle cx="23" cy="19" r="2" fill="${accent}"/>`,
  book:`<path d="M3 5c7-2 11 1 14 4v19c-4-4-8-5-14-3zM31 5c-7-2-11 1-14 4v19c4-4 8-5 14-3z" fill="#f7fbfd" ${common}/><path d="M17 9v19" ${common}/><path d="M6 11h7M6 15h7M21 11h7M21 15h7" stroke="${accent}" stroke-width="1.5"/>`,
  contract:`<path d="M5 2h19l6 6v23H5z" fill="#fff" ${common}/><path d="M24 2v7h6M9 14h17M9 19h17M9 24h10" ${common}/><path d="M20 27c3-4 6-3 9-1" fill="none" stroke="${accent}" stroke-width="2"/>`,
  calculator:`<rect x="5" y="2" width="24" height="29" rx="3" fill="#f7fbfd" ${common}/><rect x="9" y="6" width="16" height="6" rx="1" fill="${accent}" opacity=".45"/><path d="M10 17h2M17 17h2M24 17h2M10 22h2M17 22h2M24 22h2M10 27h2M17 27h9" ${common}/>` ,
  plane:`<path d="M3 18l28-13-8 22-5-8-9 5 3-9z" fill="#eef5f8" ${common}/><path d="M12 15l11-5-5 9" fill="none" stroke="${accent}" stroke-width="2.5"/>`,
  code:`<rect x="2" y="4" width="31" height="24" rx="3" fill="#eef5f8" ${common}/><path d="M12 11l-5 5 5 5M23 11l5 5-5 5M20 9l-5 15" fill="none" stroke="${accent}" stroke-width="2.5"/>`,
  calendar:`<rect x="3" y="5" width="29" height="25" rx="3" fill="#fff" ${common}/><path d="M3 12h29M10 2v7M25 2v7" ${common}/><path d="M9 17h4M18 17h4M27 17h1M9 23h4M18 23h4" stroke="${accent}" stroke-width="2"/>`,
  video:`<rect x="2" y="5" width="31" height="24" rx="4" fill="#eef5f8" ${common}/><path d="M14 11l10 6-10 6z" fill="${accent}"/>`,
  "data-grid":`<circle cx="7" cy="8" r="3" fill="${accent}"/><circle cx="18" cy="5" r="3" fill="${accent}"/><circle cx="28" cy="12" r="3" fill="${accent}"/><circle cx="12" cy="23" r="3" fill="${accent}"/><circle cx="27" cy="25" r="3" fill="${accent}"/><path d="M9 7l6-1M20 7l6 4M9 11l2 9M14 22l10 2M14 21l11-7" fill="none" ${common}/>` ,
  presentation:`<rect x="2" y="3" width="31" height="22" rx="2" fill="#fff" ${common}/><path d="M17 25v6M10 31h15" ${common}/><rect x="7" y="9" width="8" height="10" fill="${accent}" opacity=".7"/><path d="M19 10h9M19 15h7M19 20h9" ${common}/>` ,
  document:`<path d="M5 2h19l7 7v22H5z" fill="#fff" ${common}/><path d="M24 2v8h7M10 15h16M10 20h16M10 25h11" ${common}/>`
};return `<g transform="translate(${x} ${y}) scale(${scale})">${drawings[name]||drawings.document}</g>`;}
function summaryArtData(file){const spec=documentVisualSpec(file);const accents={teal:"#08a6a6",blue:"#2d72b8",purple:"#7259c7",green:"#3c996b",orange:"#d48735",red:"#c95c5c"};const accent=accents[spec.accent]||accents.teal;const motifs=[spec.primaryMotif,...(spec.secondaryMotifs||[])].slice(0,4);const positions=[[14,20,1.15],[57,45,1.18],[14,84,.9],[65,88,.9]];const artwork=motifs.map((motif,index)=>motifMarkup(motif,...positions[index],accent)).join("");const label=esc(String(spec.label||file.subcategory||file.category).toUpperCase().slice(0,20));const svg=`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 120 150"><rect x="5" y="5" width="108" height="138" rx="13" fill="#fff" stroke="#0b3a68" stroke-width="4"/><path d="M82 6l30 29H91c-5 0-9-4-9-9z" fill="#2d72b8" stroke="#0b3a68" stroke-width="3" stroke-linejoin="round"/><path d="M17 131h86" stroke="#b7c6d1" stroke-width="2"/><text x="60" y="140" text-anchor="middle" font-family="Segoe UI,Arial" font-size="7" font-weight="700" letter-spacing=".5" fill="#0b3a68">${label}</text>${artwork}</svg>`;return `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`;}
function fileIconMarkup(file){if(imageExtensions.has(file.extension)){const thumbnail=state.thumbnailCache.get(file.relativePath)||"";return `<span class="file-icon image-thumbnail${thumbnail?"":" thumb-loading"}"><img ${thumbnail?`src="${thumbnail}"`:`data-thumbnail="${esc(file.relativePath)}"`} alt="Thumbnail of ${esc(file.name)}"></span>`;}if(state.summaryArtFolders.has(state.folder))return `<span class="file-icon summary-art"><img src="${summaryArtData(file)}" alt="Document-specific summary artwork for ${esc(file.name)}"></span>`;return `<span class="file-icon ${iconClass(file.extension)}">${esc(file.extension.slice(1).toUpperCase())}</span>`;}
function queueVisibleThumbnails(files){for(const file of files){if(!imageExtensions.has(file.extension)||state.thumbnailCache.has(file.relativePath)||state.thumbnailLoading.has(file.relativePath))continue;state.thumbnailLoading.add(file.relativePath);window.lifeLibrary.thumbnail(file.relativePath).then(dataUrl=>{state.thumbnailCache.set(file.relativePath,dataUrl);document.querySelectorAll("[data-thumbnail]").forEach(image=>{if(image.dataset.thumbnail!==file.relativePath)return;image.src=dataUrl;image.removeAttribute("data-thumbnail");image.closest(".image-thumbnail")?.classList.remove("thumb-loading");});}).catch(()=>{}).finally(()=>state.thumbnailLoading.delete(file.relativePath));}}

function folders(){const found=new Set();for(const file of state.files){const parts=parentOf(file).split("\\").filter(Boolean);for(let i=1;i<=parts.length;i++)found.add(parts.slice(0,i).join("\\"));}return [...found].sort();}
function visibleFiles(){const q=state.query.toLowerCase();return state.files.filter(file=>parentOf(file)===state.folder&&(!q||`${file.name} ${file.summary} ${file.category}`.toLowerCase().includes(q)));}
function childFolders(){const prefix=state.folder?`${state.folder}\\`:"";return folders().filter(folder=>folder.startsWith(prefix)&&folder!==state.folder&&!folder.slice(prefix.length).includes("\\"));}
function folderName(folder){return folder?folder.split("\\").at(-1):"All files";}

function renderFolders(){els.allCount.textContent=state.files.length;els.tree.innerHTML=folders().map(folder=>{const depth=Math.min(folder.split("\\").length-1,2);const count=state.files.filter(file=>parentOf(file)===folder).length;return `<button class="folder-row depth-${depth}${state.folder===folder?" selected":""}" data-folder="${esc(folder)}"><span>▸</span><strong>${esc(folderName(folder))}</strong><em>${count}</em></button>`;}).join("");document.querySelector('[data-folder=""]')?.classList.toggle("selected",state.folder==="");}
function renderFiles(){const files=visibleFiles();const children=childFolders();els.title.textContent=folderName(state.folder)==="All files"?"Files":folderName(state.folder);els.path.textContent=state.folder?folderName(state.folder):"Files";els.subtitle.textContent=state.folder?`Inside Files/${state.folder.replaceAll("\\","/")}`:"Your complete read-only library";$("#back-folder").disabled=!state.folder;$("#visualize-folder").classList.toggle("active",state.summaryArtFolders.has(state.folder));$("#visualize-folder").textContent=state.summaryArtFolders.has(state.folder)?"▣ Restore Icons":"✦ AI Visuals";const folderRows=children.map(folder=>{const contained=state.files.filter(file=>parentOf(file)===folder||parentOf(file).startsWith(`${folder}\\`)).length;return `<div class="file-row" data-open-folder="${esc(folder)}"><div class="file-main folder-row-main"><span class="file-icon folder-icon">&#128193;</span><div class="file-info"><div class="file-name">${esc(folderName(folder))}</div><div class="file-summary">${contained} contained item${contained===1?"":"s"}</div></div></div><span class="folder-row-middle">Folder</span></div>`;}).join("");const fileRows=files.map(file=>`<div class="file-row${state.selected===file.relativePath?" selected":""}" data-file="${esc(file.relativePath)}"><div class="file-main">${fileIconMarkup(file)}<div class="file-info"><div class="file-name">${esc(file.name)}</div><div class="file-summary">${esc(file.summary)}</div></div></div><span class="pill" title="${esc(categoryTrail(file))}">${esc(categoryTrail(file))}</span><span class="file-size">${bytes(file.bytes)}</span></div>`).join("");els.list.innerHTML=folderRows+fileRows;const total=children.length+files.length;els.empty.hidden=total>0;els.count.textContent=`${total} item${total===1?"":"s"}`;queueVisibleThumbnails(files);}
function render(){renderFolders();renderFiles();}
function relativeTime(timestamp){if(!timestamp)return "No activity recorded";const elapsed=Math.max(0,Date.now()-Number(timestamp));const minutes=Math.floor(elapsed/60000);if(minutes<1)return "Just now";if(minutes<60)return `${minutes}m ago`;const hours=Math.floor(minutes/60);if(hours<24)return `${hours}h ago`;const days=Math.floor(hours/24);if(days<30)return `${days}d ago`;return new Date(timestamp).toLocaleDateString();}
function dashboardSearchMatches(query){const tokens=query.toLowerCase().split(/[^\p{L}\p{N}]+/u).filter(token=>token.length>1);if(!tokens.length)return [];return state.files.map(file=>{const name=file.name.toLowerCase();const summary=(file.summary||"").toLowerCase();const taxonomy=`${file.category} ${file.subcategory||""}`.toLowerCase();const signals=`${(file.tags||[]).join(" ")} ${(file.evidence||[]).join(" ")}`.toLowerCase();const filePath=file.relativePath.toLowerCase();let score=0;for(const token of tokens){if(name.includes(token))score+=8;if(signals.includes(token))score+=5;if(taxonomy.includes(token))score+=4;if(summary.includes(token))score+=3;if(filePath.includes(token))score+=1;}return {file,score};}).filter(result=>result.score>0).sort((a,b)=>b.score-a.score||b.file.modifiedMs-a.file.modifiedMs);}
function renderDashboardSearch(){const root=$("#dashboard-search-results");const query=state.dashboardQuery.trim();if(!query){root.hidden=true;root.innerHTML="";return;}const matches=dashboardSearchMatches(query);root.hidden=false;root.innerHTML=matches.slice(0,6).map(({file})=>`<button class="dashboard-search-result" data-dashboard-file="${esc(file.relativePath)}"><span class="file-icon ${iconClass(file.extension)}">${esc(file.extension.slice(1).toUpperCase())}</span><span><strong>${esc(file.name)}</strong><small>${esc(file.summary)}</small></span><em>${esc(file.category)}</em></button>`).join("")+(matches.length?`<button class="search-show-all" data-search-show-all>View all ${matches.length} results · Enter</button>`:'<div class="dashboard-search-empty">No summaries or file details matched those keywords.</div>');}
function renderSearchDetail(file){const root=$("#search-dialog-detail");if(!file){root.innerHTML='<div class="search-detail-empty">Select a result to review its complete summary and file details.</div>';return;}root.innerHTML=`<span class="search-detail-icon ${iconClass(file.extension)}">${esc(file.extension.slice(1).toUpperCase())}</span><h3>${esc(file.name)}</h3><div class="search-detail-category">${esc(categoryTrail(file))}</div><div class="search-detail-summary">${esc(file.summary)}</div><dl class="search-detail-meta"><dt>Location</dt><dd>Files/${esc(file.relativePath.replaceAll("\\","/"))}</dd><dt>Type</dt><dd>${esc(file.extension.toUpperCase().slice(1)||"File")}</dd><dt>Size</dt><dd>${bytes(file.bytes)}</dd><dt>Modified</dt><dd>${new Date(file.modifiedMs).toLocaleString()}</dd><dt>Created</dt><dd>${new Date(file.createdMs).toLocaleString()}</dd></dl><div class="search-detail-actions"><button data-search-open-file="${esc(file.relativePath)}">Open file</button><button class="primary" data-search-show-explorer="${esc(file.relativePath)}">Show in Explorer</button></div>`;}
function openSearchDialog(){const query=state.dashboardQuery.trim();if(!query)return;const matches=dashboardSearchMatches(query);$("#search-dialog-title").textContent=`${matches.length} result${matches.length===1?"":"s"} for “${query}”`;$("#search-dialog-results").innerHTML=matches.map(({file})=>`<button class="search-result-row" data-search-detail-file="${esc(file.relativePath)}"><span class="file-icon ${iconClass(file.extension)}">${esc(file.extension.slice(1).toUpperCase())}</span><span><strong>${esc(file.name)}</strong><p>${esc(file.summary)}</p><small>${esc(categoryTrail(file))} · Files/${esc(file.relativePath.replaceAll("\\","/"))}</small></span></button>`).join("")||'<div class="dashboard-search-empty">No matching files.</div>';renderSearchDetail(matches[0]?.file);$("#search-dialog-results").querySelector("[data-search-detail-file]")?.classList.add("selected");$("#search-dialog").showModal();}
function renderDashboard(){const categories=new Set(state.files.map(file=>file.category));$("#dash-files").textContent=state.files.length;$("#dash-categories").textContent=categories.size;const timestamps={opened:file=>Number(file.lastOpenedAt)||0,edited:file=>Number(file.modifiedMs)||0,created:file=>Number(file.createdMs)||0};const descriptions={opened:"Files most recently opened from LifeLibrary",edited:"Files most recently edited on disk",created:"Files most recently created on disk"};document.querySelectorAll("[data-recent-mode]").forEach(button=>button.classList.toggle("active",button.dataset.recentMode===state.recentMode));$("#recent-description").textContent=descriptions[state.recentMode];const recent=state.files.filter(file=>timestamps[state.recentMode](file)>0).sort((a,b)=>timestamps[state.recentMode](b)-timestamps[state.recentMode](a)).slice(0,6);$("#recent-files").innerHTML=recent.map(file=>`<button class="recent-card" data-dashboard-file="${esc(file.relativePath)}"><span class="file-icon ${iconClass(file.extension)}">${esc(file.extension.slice(1).toUpperCase())}</span><span class="file-info"><span class="file-name">${esc(file.name)}</span><span class="file-summary">${esc(file.summary)}</span><span class="recent-card-time">${relativeTime(timestamps[state.recentMode](file))} · ${esc(categoryTrail(file))}</span></span></button>`).join("")||`<div class="empty"><p>No recently ${state.recentMode} files yet.</p></div>`;renderDashboardSearch();}
function setView(view){const explorer=view==="explorer";const recycle=view==="recycle";const settings=view==="settings";const categories=view==="categories";const connections=view==="connections";document.body.classList.toggle("explorer-mode",explorer);document.body.classList.toggle("recycle-mode",recycle);document.body.classList.toggle("settings-mode",settings);document.body.classList.toggle("categories-mode",categories);document.body.classList.toggle("connections-mode",connections);document.querySelectorAll("[data-view]").forEach(button=>button.classList.toggle("active",button.dataset.view===view));if(explorer&&!state.selected)showFolderOverview();if(recycle)loadRecycle();if(settings)loadSettingsUI();if(categories)renderCategoryShelves();if(connections)renderUniverse();}
async function focusFileInExplorer(relativePath){const file=state.files.find(item=>item.relativePath===relativePath);if(!file)return;state.folder=parentOf(file);setView("explorer");render();await selectFile(relativePath);}
async function openFile(relativePath){await window.lifeLibrary.open(relativePath);const file=state.files.find(item=>item.relativePath===relativePath);if(file)file.lastOpenedAt=Date.now();renderDashboard();}

async function selectFile(relativePath){const file=state.files.find(item=>item.relativePath===relativePath);if(!file)return;state.selected=relativePath;renderFiles();els.previewEmpty.hidden=true;els.previewContent.hidden=false;els.previewPane.classList.add("open");$("#preview-name").textContent=file.name;$("#preview-icon").textContent=file.extension.slice(1).toUpperCase();$("#preview-meta").textContent=`${categoryTrail(file)} · ${bytes(file.bytes)}`;$("#preview-summary").textContent=file.summary;$("#preview-category").textContent=file.category;$("#preview-subcategory").textContent=file.subcategory?`› ${file.subcategory}`:"";$("#preview-confidence").textContent=`${Math.round(file.confidence*100)}% confidence`;$("#preview-evidence").innerHTML=file.evidence.map(word=>`<span>${esc(word)}</span>`).join("");$("#detail-path").textContent=`Files/${file.relativePath.replaceAll("\\","/")}`;$("#detail-type").textContent=file.extension.toUpperCase().slice(1)||"File";$("#detail-size").textContent=bytes(file.bytes);const body=$("#preview-body");body.classList.add("loading");body.innerHTML="Loading preview…";try{const preview=await window.lifeLibrary.preview(file.relativePath);if(preview.kind==="image")body.innerHTML=`<img src="${preview.content}" alt="Preview of ${esc(file.name)}">`;else if(preview.kind==="text")body.textContent=preview.content+(preview.truncated?"\n\n[Preview truncated]":"");else body.innerHTML=`<div class="unsupported">${esc(preview.content)}</div>`;}catch{body.innerHTML='<div class="unsupported">Preview could not be loaded.</div>';}finally{body.classList.remove("loading");}}
function showFolderOverview(){const direct=state.files.filter(file=>parentOf(file)===state.folder);const nested=state.files.filter(file=>state.folder===""||parentOf(file)===state.folder||parentOf(file).startsWith(`${state.folder}\\`));const categories=new Set(nested.map(file=>file.category));els.previewEmpty.innerHTML=`<span class="preview-glyph">▤</span><h2>${esc(state.folder?folderName(state.folder):"Files")}</h2><p>${esc(state.folder?`Files/${state.folder.replaceAll("\\","/")}`:state.libraryRoot.replaceAll("\\","/"))}</p><div class="folder-stats"><div class="folder-stat"><strong>${direct.length}</strong><span>Direct files</span></div><div class="folder-stat"><strong>${childFolders().length}</strong><span>Folders</span></div><div class="folder-stat"><strong>${nested.length}</strong><span>Total files</span></div><div class="folder-stat"><strong>${categories.size}</strong><span>Categories</span></div></div>`;}
function showSelectedFolder(folder){state.selected=null;els.previewContent.hidden=true;els.previewEmpty.hidden=false;const direct=state.files.filter(file=>parentOf(file)===folder);const nested=state.files.filter(file=>parentOf(file)===folder||parentOf(file).startsWith(`${folder}\\`));const immediateFolders=folders().filter(candidate=>candidate.startsWith(`${folder}\\`)&&!candidate.slice(folder.length+1).includes("\\"));const categories=new Set(nested.map(file=>file.category));els.previewEmpty.innerHTML=`<span class="preview-glyph">▤</span><h2>${esc(folderName(folder))}</h2><p>${esc(`Files/${folder.replaceAll("\\","/")}`)}</p><div class="folder-stats"><div class="folder-stat"><strong>${direct.length}</strong><span>Direct files</span></div><div class="folder-stat"><strong>${immediateFolders.length}</strong><span>Folders</span></div><div class="folder-stat"><strong>${nested.length}</strong><span>Total files</span></div><div class="folder-stat"><strong>${categories.size}</strong><span>Categories</span></div></div>`;}
function chooseFolder(folder){state.folder=folder;state.selected=null;els.previewEmpty.hidden=false;els.previewContent.hidden=true;els.previewPane.classList.remove("open");render();showFolderOverview();}
async function load(){els.refresh.disabled=true;$("#dashboard-refresh").disabled=true;try{const data=await window.lifeLibrary.scan();state.files=data.files;state.libraryRoot=data.libraryRoot||state.libraryRoot;const privacyPath=document.querySelector(".privacy p");if(privacyPath)privacyPath.textContent=`Browsing ${state.libraryRoot} safely`;render();renderDashboard();showFolderOverview();updateTaxonomyStatus();}finally{els.refresh.disabled=false;$("#dashboard-refresh").disabled=false;}}
async function analyzeBatch(files,button,label){if(state.batchAnalyzing)return {completed:0,failed:0};state.batchAnalyzing=true;button.disabled=true;let completed=0;let failed=0;try{const pending=files.filter(file=>!file.aiPersisted);for(let index=0;index<pending.length;index++){button.textContent=`${label} ${index+1}/${pending.length}`;if(await analyzeFile(pending[index].relativePath,{silent:true}))completed++;else failed++;}return {completed,failed,pending:pending.length};}finally{state.batchAnalyzing=false;}}
async function scanAndOrganizeLibrary(){const button=$("#dashboard-refresh");if(state.batchAnalyzing)return;const original=button.textContent;button.disabled=true;button.textContent="Scanning files…";try{await load();const result=await analyzeBatch(state.files,button,"AI organizing");await load();if(!result.pending)showToast("Library is already fully analyzed");else showToast(`AI organized ${result.completed} file${result.completed===1?"":"s"}${result.failed?`; ${result.failed} could not be analyzed`:""}`);}catch(error){showToast(error?.message||"Library scan failed.");}finally{button.disabled=false;button.textContent=original;}}
async function visualizeCurrentFolder(){const button=$("#visualize-folder");if(state.batchAnalyzing)return;if(state.summaryArtFolders.has(state.folder)){state.summaryArtFolders.delete(state.folder);renderFiles();return;}button.disabled=true;state.batchAnalyzing=true;let completed=0;let failed=0;try{await load();const files=state.files.filter(file=>parentOf(file)===state.folder);const documents=files.filter(file=>!imageExtensions.has(file.extension));for(let index=0;index<documents.length;index++){const file=documents[index];button.textContent=`Illustrating ${index+1}/${documents.length}`;if(!file.aiPersisted&&!await analyzeFile(file.relativePath,{silent:true})){failed++;continue;}try{file.visual=await window.lifeLibrary.visualize(file.relativePath);completed++;}catch{failed++;}}state.summaryArtFolders.add(state.folder);renderFiles();showToast(`${completed} document illustration${completed===1?"":"s"} ready; image thumbnails were preserved${failed?`; ${failed} failed`:""}`);}catch(error){showToast(error?.message||"Folder visuals could not be created.");}finally{state.batchAnalyzing=false;button.disabled=false;renderFiles();}}
function showToast(message){const toast=$("#toast");toast.textContent=message;toast.hidden=false;window.clearTimeout(showToast.timer);showToast.timer=window.setTimeout(()=>{toast.hidden=true;},3200);}
function requestRename(currentName){const dialog=$("#rename-dialog");const input=$("#rename-input");input.value=currentName;dialog.returnValue="cancel";dialog.showModal();window.setTimeout(()=>{input.focus();input.select();},0);return new Promise(resolve=>dialog.addEventListener("close",()=>resolve(dialog.returnValue==="default"?input.value:null),{once:true}));}
async function analyzeFile(relativePath,{announce=false,silent=false}={}){const existing=state.files.find(item=>item.relativePath===relativePath);if(!relativePath||state.analysisInFlight.has(relativePath))return false;if(!announce&&existing?.aiPersisted)return true;state.analysisInFlight.add(relativePath);const button=$("#analyze-local");if(state.selected===relativePath){button.disabled=true;button.textContent="AI is analyzing…";}try{const analysis=await window.lifeLibrary.analyze(relativePath);const file=state.files.find(item=>item.relativePath===relativePath);if(!file)return false;file.category=analysis.category;file.subcategory=analysis.subcategory||"";file.summary=analysis.summary;file.confidence=analysis.confidence;file.evidence=[...analysis.evidence,...analysis.tags].slice(0,6);file.tags=analysis.tags;file.aiPersisted=analysis.category.toLowerCase()!=="uncategorized";renderFiles();renderDashboard();if(document.body.classList.contains("categories-mode"))renderCategoryShelves();if(document.body.classList.contains("connections-mode"))renderUniverse();if(state.selected===relativePath){$("#preview-summary").textContent=file.summary;$("#preview-category").textContent=file.category;$("#preview-subcategory").textContent=file.subcategory?`› ${file.subcategory}`:"";$("#preview-confidence").textContent=`${Math.round(file.confidence*100)}% confidence`;$("#preview-evidence").innerHTML=file.evidence.map(word=>`<span>${esc(word)}</span>`).join("");}if(announce)showToast(`${analysis.cached?"Loaded cached result from":"Analyzed with"} ${analysis.model}`);return true;}catch(error){if(!silent)showToast(error?.message||"AI analysis failed.");return false;}finally{state.analysisInFlight.delete(relativePath);if(state.selected===relativePath){button.disabled=false;button.textContent="Analyze again";}}}
async function loadRecycle(){const list=$("#recycle-list");const empty=$("#recycle-empty");list.innerHTML='<div class="recycle-date">Loading recycle bin…</div>';try{const items=await window.lifeLibrary.recycleList();$("#recycle-count").textContent=items.length||"";list.innerHTML=items.map(item=>`<article class="recycle-item" data-recycle-id="${esc(item.id)}"><span class="recycle-icon">${item.isDirectory?"DIR":esc(item.name.split(".").at(-1).slice(0,5).toUpperCase())}</span><div class="recycle-info"><div class="recycle-name">${esc(item.name)}</div><div class="recycle-path">${esc(item.originalPath)}</div></div><div class="recycle-date">Deleted ${new Date(item.deletedAt).toLocaleString()}</div><div class="recycle-actions"><button class="restore" data-recycle-action="restore">Restore</button><button class="purge" data-recycle-action="purge">Delete permanently</button></div></article>`).join("");empty.hidden=items.length>0;list.hidden=items.length===0;}catch(error){list.innerHTML=`<div class="recycle-date">${esc(error?.message||"Recycle Bin could not be loaded.")}</div>`;}}
function selectedProvider(){return document.querySelector('input[name="provider"]:checked')?.value||"lmstudio";}
function showProviderPanel(provider){document.querySelectorAll("[data-provider-panel]").forEach(panel=>panel.hidden=panel.dataset.providerPanel!==provider);}
function applyTheme(theme){state.theme=theme;document.body.dataset.theme=theme;document.querySelectorAll("[data-theme-choice]").forEach(button=>button.classList.toggle("active",button.dataset.themeChoice===theme));}
function updateTaxonomyStatus(){const min=Math.max(2,Number($("#category-min").value)||10);const max=Math.max(min,Number($("#category-max").value)||15);const current=new Set(state.files.map(file=>file.category).filter(category=>category&&category.toLowerCase()!=="uncategorized")).size;$("#taxonomy-status").textContent=`${current} top-level categories now · target ${min}–${max}`;}
async function loadSettingsUI(){try{const settings=await window.lifeLibrary.getSettings();state.settings=settings;document.querySelector(`input[name="provider"][value="${settings.provider}"]`).checked=true;$("#library-path").value=settings.libraryPath||state.libraryRoot;$("#local-endpoint").value=settings.localEndpoint;$("#local-model").value=settings.localModel;$("#openai-model").value=settings.openaiModel;$("#openai-key").value="";$("#category-min").value=settings.categoryMin;$("#category-max").value=settings.categoryMax;$("#key-status").textContent=settings.hasOpenAIKey?"An encrypted API key is saved":"No API key saved";showProviderPanel(settings.provider);applyTheme(settings.theme);updateTaxonomyStatus();}catch(error){showToast(error?.message||"Settings could not be loaded.");}}
function settingsFromForm(){return {provider:selectedProvider(),libraryPath:$("#library-path").value.trim(),localEndpoint:$("#local-endpoint").value.trim(),localModel:$("#local-model").value.trim(),openaiModel:$("#openai-model").value.trim(),openaiApiKey:$("#openai-key").value.trim(),theme:state.theme,categoryMin:Number($("#category-min").value),categoryMax:Number($("#category-max").value)};}
async function applyCategoryRange(){const button=$("#apply-category-range");button.disabled=true;button.textContent="Rebalancing…";try{const settings=await window.lifeLibrary.saveSettings(settingsFromForm());state.settings=settings;$("#category-min").value=settings.categoryMin;$("#category-max").value=settings.categoryMax;await load();state.categoryFocus=null;renderCategoryShelves();updateTaxonomyStatus();showToast(`Category range updated to ${settings.categoryMin}–${settings.categoryMax}`);}catch(error){showToast(error?.message||"Category range could not be updated.");}finally{button.disabled=false;button.textContent="Apply & rebalance";}}
async function runContextAction(action){const target=state.contextTarget;if(!target)return;try{if(action==="open"){if(target.kind==="folder")chooseFolder(target.path);else await openFile(target.path);}else if(action==="reveal"){await window.lifeLibrary.reveal(target.path);}else if(action==="rename"){const next=await requestRename(target.name);if(!next||next===target.name)return;await window.lifeLibrary.rename(target.path,next);state.selected=null;await load();showToast(`Renamed to ${next}`);}else if(action==="delete"){const confirmed=window.confirm(`Move ${target.name} to LifeLibrary quarantine?\n\nThis is recoverable and will not permanently erase the item.`);if(!confirmed)return;await window.lifeLibrary.delete(target.path);state.selected=null;await load();showToast(`${target.name} moved to quarantine`);}}catch(error){showToast(error?.message||"The action could not be completed.");}}

function categoryGroups(){const groups=new Map();for(const file of state.files){if(!groups.has(file.category))groups.set(file.category,[]);groups.get(file.category).push(file);}return [...groups.entries()].sort((a,b)=>b[1].length-a[1].length||a[0].localeCompare(b[0]));}
function renderCategoryShelvesLegacy(){const root=$("#category-shelves");const groups=categoryGroups();if(state.categoryFocus){const match=groups.find(([category])=>category===state.categoryFocus);if(!match){state.categoryFocus=null;return renderCategoryShelves();}const [category,files]=match;root.innerHTML=`<article class="category-shelf" data-category-back><div class="category-shelf-head"><span>←</span><strong>All categories</strong></div></article><article class="category-shelf"><div class="category-shelf-head"><span class="category-dot" style="--category-color:var(--cat-${groups.indexOf(match)%8})"></span><strong>${esc(category)}</strong><em>${files.length} files</em></div><div class="category-preview-files">${files.map(file=>`<button class="category-preview-file" data-category-file="${esc(file.relativePath)}"><span class="file-icon ${iconClass(file.extension)}">${esc(file.extension.slice(1).toUpperCase())}</span><span>${esc(file.name)}</span></button>`).join("")}</div></article>`;return;}root.innerHTML=groups.map(([category,files],index)=>`<article class="category-shelf" data-category-open="${esc(category)}"><div class="category-shelf-head"><span class="category-dot" style="--category-color:var(--cat-${index%8})"></span><strong>${esc(category)}</strong><em>${files.length}</em></div><div class="category-preview-files">${files.slice(0,5).map(file=>`<div class="category-preview-file"><span class="file-icon ${iconClass(file.extension)}">${esc(file.extension.slice(1).toUpperCase())}</span><span>${esc(file.name)}</span></div>`).join("")}</div>${files.length>5?`<div class="category-more">+ ${files.length-5} more files</div>`:""}</article>`).join("")||'<div class="recycle-empty"><h2>No categories yet</h2></div>';}
function renderCategoryShelves(){const root=$("#category-shelves");const groups=categoryGroups();if(!state.categoryFocus){root.classList.remove("detail-mode");root.innerHTML=groups.map(([category,files],index)=>`<article class="category-shelf" data-category-open="${esc(category)}"><div class="category-shelf-head"><span class="category-dot" style="--category-color:var(--cat-${index%8})"></span><strong>${esc(category)}</strong><em>${files.length}</em></div><div class="category-preview-files">${files.slice(0,5).map(file=>`<div class="category-preview-file"><span class="file-icon ${iconClass(file.extension)}">${esc(file.extension.slice(1).toUpperCase())}</span><span>${esc(file.name)}</span></div>`).join("")}</div>${files.length>5?`<div class="category-more">+ ${files.length-5} more files</div>`:""}</article>`).join("")||'<div class="recycle-empty"><h2>No categories yet</h2></div>';return;}const match=groups.find(([category])=>category===state.categoryFocus);if(!match){state.categoryFocus=null;return renderCategoryShelves();}const [category,files]=match;const subgroups=new Map();for(const file of files){const subcategory=file.subcategory&&file.subcategory.toLowerCase()!==category.toLowerCase()?file.subcategory:"General";if(!subgroups.has(subcategory))subgroups.set(subcategory,[]);subgroups.get(subcategory).push(file);}const sections=[...subgroups.entries()].sort((a,b)=>b[1].length-a[1].length||a[0].localeCompare(b[0])).map(([subcategory,items])=>`<section class="category-detail-group"><div class="category-detail-group-head"><h3>${esc(subcategory)}</h3><span>${items.length} file${items.length===1?"":"s"}</span></div><div class="category-file-grid">${items.map(file=>`<button class="category-file-card" data-category-file="${esc(file.relativePath)}"><span class="category-file-card-head"><span class="file-icon ${iconClass(file.extension)}">${esc(file.extension.slice(1).toUpperCase())}</span><span><strong>${esc(file.name)}</strong><small>${esc(file.extension.toUpperCase().slice(1)||"FILE")} · ${bytes(file.bytes)}</small></span></span><span class="category-file-card-summary">${esc(file.summary)}</span><span class="category-file-card-path">Files/${esc(file.relativePath.replaceAll("\\","/"))}</span></button>`).join("")}</div></section>`).join("");root.classList.add("detail-mode");root.innerHTML=`<section class="category-detail"><header class="category-detail-head"><button data-category-back>← All categories</button><div><span class="category-dot" style="--category-color:var(--cat-${groups.indexOf(match)%8})"></span><h2>${esc(category)}</h2><p>${files.length} file${files.length===1?"":"s"} across ${subgroups.size} subcategor${subgroups.size===1?"y":"ies"}</p></div></header>${sections}</section>`;}
function relationTokens(file){return new Set(`${file.name} ${file.relativePath} ${file.subcategory||""} ${(file.evidence||[]).join(" ")}`.toLowerCase().split(/[^a-z0-9]+/).filter(token=>token.length>3&&!['file','with','from','this','that','report'].includes(token)));}
function renderUniverseLegacy(){const svg=$("#file-universe");const groups=categoryGroups();const files=state.files.slice(0,100);$("#universe-total").textContent=state.files.length;$("#category-filters").innerHTML=groups.map(([category,list],index)=>`<button class="category-filter${state.connectionFilter===category?" active":""}" data-category-filter="${esc(category)}"><span class="category-dot" style="--category-color:var(--cat-${index%8})"></span><strong>${esc(category)}</strong><em>${list.length}</em></button>`).join("");document.querySelector('[data-category-filter="all"]')?.classList.toggle("active",state.connectionFilter==="all");if(!files.length){svg.innerHTML='<text x="450" y="285" text-anchor="middle" class="universe-empty">No files to connect yet</text>';return;}const hubs=new Map();groups.forEach(([category,list],index)=>{const angle=-Math.PI/2+(index/groups.length)*Math.PI*2;hubs.set(category,{x:450+Math.cos(angle)*285,y:270+Math.sin(angle)*185,index,count:list.length});});const nodes=files.map(file=>{const hub=hubs.get(file.category);const siblings=groups.find(([category])=>category===file.category)?.[1].filter(item=>files.includes(item))||[];const localIndex=siblings.indexOf(file);const angle=(localIndex/Math.max(1,siblings.length))*Math.PI*2+(hub.index*.6);const ring=38+Math.floor(localIndex/12)*22;return {file,x:hub.x+Math.cos(angle)*ring,y:hub.y+Math.sin(angle)*ring,tokens:relationTokens(file)};});const edges=[];for(let i=0;i<nodes.length;i++){for(let j=i+1;j<nodes.length&&edges.length<120;j++){const a=nodes[i],b=nodes[j];if(a.file.category===b.file.category)continue;const shared=[...a.tokens].filter(token=>b.tokens.has(token));if((parentOf(a.file)===parentOf(b.file)&&parentOf(a.file)!=="")||shared.length>=2)edges.push([a,b]);}}const filtered=state.connectionFilter;const opacity=category=>filtered==="all"||category===filtered?1:.13;svg.innerHTML=`${nodes.map(node=>{const hub=hubs.get(node.file.category);return `<line class="universe-edge" x1="${hub.x.toFixed(1)}" y1="${hub.y.toFixed(1)}" x2="${node.x.toFixed(1)}" y2="${node.y.toFixed(1)}" opacity="${opacity(node.file.category)*.17}"></line>`;}).join("")}${edges.map(([a,b])=>`<line class="universe-edge related" x1="${a.x.toFixed(1)}" y1="${a.y.toFixed(1)}" x2="${b.x.toFixed(1)}" y2="${b.y.toFixed(1)}" opacity="${Math.min(opacity(a.file.category),opacity(b.file.category))*.24}"></line>`).join("")}${groups.map(([category],index)=>{const hub=hubs.get(category);return `<g opacity="${opacity(category)}"><circle class="universe-hub" cx="${hub.x}" cy="${hub.y}" r="17" fill="var(--cat-${index%8})"></circle><text class="universe-label" x="${hub.x}" y="${hub.y+31}" text-anchor="middle">${esc(category.slice(0,22))}</text><text class="universe-count" x="${hub.x}" y="${hub.y+43}" text-anchor="middle">${hub.count} files</text></g>`;}).join("")}${nodes.map(node=>`<circle class="universe-node${state.universeSelection===node.file.relativePath?" selected":""}" data-universe-file="${esc(node.file.relativePath)}" cx="${node.x.toFixed(1)}" cy="${node.y.toFixed(1)}" r="5.5" fill="var(--cat-${hubs.get(node.file.category).index%8})" opacity="${opacity(node.file.category)}"><title>${esc(node.file.name)} — ${esc(node.file.category)}</title></circle>`).join("")}`;}

function applyUniverseTransform(){const viewport=$("#universe-viewport");if(viewport)viewport.setAttribute("transform",`translate(${state.universeView.x.toFixed(2)} ${state.universeView.y.toFixed(2)}) scale(${state.universeView.scale.toFixed(3)})`);$("#universe-zoom-level").textContent=`${Math.round(state.universeView.scale*100)}%`;}
function zoomUniverseTo(nextScale,anchor={x:450,y:285}){const oldScale=state.universeView.scale;const scale=Math.max(.5,Math.min(4,nextScale));state.universeView.x=anchor.x-(anchor.x-state.universeView.x)*(scale/oldScale);state.universeView.y=anchor.y-(anchor.y-state.universeView.y)*(scale/oldScale);state.universeView.scale=scale;applyUniverseTransform();}
function resetUniverseView(){state.universeView={x:0,y:0,scale:1};applyUniverseTransform();}
function universePoint(event){const rect=$("#file-universe").getBoundingClientRect();return {x:(event.clientX-rect.left)*900/rect.width,y:(event.clientY-rect.top)*570/rect.height};}

function renderUniverse(){
  const svg=$("#file-universe");
  const groups=categoryGroups();
  const files=state.files.slice(0,100);
  $("#universe-total").textContent=state.files.length;
  $("#category-filters").innerHTML=groups.map(([category,list],index)=>`<button class="category-filter${state.connectionFilter===category?" active":""}" data-category-filter="${esc(category)}"><span class="category-dot" style="--category-color:var(--cat-${index%8})"></span><strong>${esc(category)}</strong><em>${list.length}</em></button>`).join("");
  document.querySelector('[data-category-filter="all"]')?.classList.toggle("active",state.connectionFilter==="all");
  if(!files.length){svg.innerHTML='<text x="450" y="285" text-anchor="middle" class="universe-empty">No files to connect yet</text>';return;}
  const hubs=new Map();
  groups.forEach(([category,list],index)=>{const angle=-Math.PI/2+(index/groups.length)*Math.PI*2;hubs.set(category,{x:450+Math.cos(angle)*285,y:270+Math.sin(angle)*185,index,count:list.length});});
  const nodes=files.map(file=>{const hub=hubs.get(file.category);const siblings=groups.find(([category])=>category===file.category)?.[1].filter(item=>files.includes(item))||[];const localIndex=siblings.indexOf(file);const angle=(localIndex/Math.max(1,siblings.length))*Math.PI*2+(hub.index*.6);const ring=38+Math.floor(localIndex/12)*22;return {file,x:hub.x+Math.cos(angle)*ring,y:hub.y+Math.sin(angle)*ring,tokens:relationTokens(file)};});
  const edges=[];
  for(let i=0;i<nodes.length;i++){for(let j=i+1;j<nodes.length&&edges.length<120;j++){const a=nodes[i],b=nodes[j];if(a.file.category===b.file.category)continue;const shared=[...a.tokens].filter(token=>b.tokens.has(token));if((parentOf(a.file)===parentOf(b.file)&&parentOf(a.file)!=="")||shared.length>=2)edges.push([a,b]);}}
  const filtered=state.connectionFilter;
  const opacity=category=>filtered==="all"||category===filtered?1:.13;
  const graph=`${nodes.map(node=>{const hub=hubs.get(node.file.category);return `<line class="universe-edge" x1="${hub.x.toFixed(1)}" y1="${hub.y.toFixed(1)}" x2="${node.x.toFixed(1)}" y2="${node.y.toFixed(1)}" opacity="${opacity(node.file.category)*.17}"></line>`;}).join("")}${edges.map(([a,b])=>`<line class="universe-edge related" x1="${a.x.toFixed(1)}" y1="${a.y.toFixed(1)}" x2="${b.x.toFixed(1)}" y2="${b.y.toFixed(1)}" opacity="${Math.min(opacity(a.file.category),opacity(b.file.category))*.24}"></line>`).join("")}${groups.map(([category],index)=>{const hub=hubs.get(category);return `<g opacity="${opacity(category)}"><circle class="universe-hub" cx="${hub.x}" cy="${hub.y}" r="17" fill="var(--cat-${index%8})"></circle><text class="universe-label" x="${hub.x}" y="${hub.y+31}" text-anchor="middle">${esc(category.slice(0,22))}</text><text class="universe-count" x="${hub.x}" y="${hub.y+43}" text-anchor="middle">${hub.count} files</text></g>`;}).join("")}${nodes.map(node=>`<circle class="universe-node${state.universeSelection===node.file.relativePath?" selected":""}" data-universe-file="${esc(node.file.relativePath)}" cx="${node.x.toFixed(1)}" cy="${node.y.toFixed(1)}" r="5.5" fill="var(--cat-${hubs.get(node.file.category).index%8})" opacity="${opacity(node.file.category)}"><title>${esc(node.file.name)} — ${esc(categoryTrail(node.file))}</title></circle>`).join("")}`;
  svg.innerHTML=`<g id="universe-viewport" class="universe-viewport">${graph}</g>`;
  applyUniverseTransform();
}

