els.list.addEventListener("click",event=>{window.clearTimeout(state.clickTimer);const folder=event.target.closest("[data-open-folder]");if(folder){state.clickTimer=window.setTimeout(()=>{document.querySelectorAll(".file-row.selected").forEach(row=>row.classList.remove("selected"));folder.classList.add("selected");showSelectedFolder(folder.dataset.openFolder);},180);return;}const row=event.target.closest("[data-file]");if(row)state.clickTimer=window.setTimeout(async()=>{await selectFile(row.dataset.file);await analyzeFile(row.dataset.file);},180);});
els.list.addEventListener("dblclick",async event=>{window.clearTimeout(state.clickTimer);const folder=event.target.closest("[data-open-folder]");if(folder)return chooseFolder(folder.dataset.openFolder);const row=event.target.closest("[data-file]");if(!row)return;try{await openFile(row.dataset.file);}catch(error){showToast(error?.message||"This file could not be opened.");}});
