$("#recycle-list").addEventListener("click",async event=>{const action=event.target.closest("[data-recycle-action]");const item=event.target.closest("[data-recycle-id]");if(!action||!item)return;try{if(action.dataset.recycleAction==="restore"){await window.lifeLibrary.recycleRestore(item.dataset.recycleId);showToast("Item restored to its original location");}else{const name=item.querySelector(".recycle-name")?.textContent||"this item";if(!window.confirm(`Permanently delete ${name}?\n\nThis cannot be undone.`))return;await window.lifeLibrary.recyclePurge(item.dataset.recycleId);showToast("Item permanently deleted");}await loadRecycle();await load();}catch(error){showToast(error?.message||"Recycle Bin action failed.");}});
