$("#save-settings").addEventListener("click",async()=>{const button=$("#save-settings");button.disabled=true;$("#settings-status").textContent="Saving…";try{const settings=await window.lifeLibrary.saveSettings(settingsFromForm());state.settings=settings;$("#category-min").value=settings.categoryMin;$("#category-max").value=settings.categoryMax;$("#openai-key").value="";$("#key-status").textContent=settings.hasOpenAIKey?"An encrypted API key is saved":"No API key saved";await load();$("#settings-status").textContent="Settings saved and categories balanced.";showToast("Settings saved; category levels updated");}catch(error){$("#settings-status").textContent=error?.message||"Settings could not be saved.";}finally{button.disabled=false;}});
