$("#universe-zoom-in").addEventListener("click",()=>zoomUniverseTo(state.universeView.scale*1.25));
$("#universe-zoom-out").addEventListener("click",()=>zoomUniverseTo(state.universeView.scale/1.25));
$("#universe-zoom-reset").addEventListener("click",resetUniverseView);
$("#file-universe").addEventListener("wheel",event=>{event.preventDefault();zoomUniverseTo(state.universeView.scale*(event.deltaY<0?1.12:.89),universePoint(event));},{passive:false});
$("#file-universe").addEventListener("pointerdown",event=>{if(event.button!==0||event.target.closest("[data-universe-file]"))return;const point=universePoint(event);state.universePan={pointerId:event.pointerId,last:point};state.universeDidPan=false;event.currentTarget.setPointerCapture(event.pointerId);event.currentTarget.classList.add("panning");});
$("#file-universe").addEventListener("pointermove",event=>{if(!state.universePan||state.universePan.pointerId!==event.pointerId)return;const point=universePoint(event);const dx=point.x-state.universePan.last.x;const dy=point.y-state.universePan.last.y;if(Math.abs(dx)+Math.abs(dy)>.5)state.universeDidPan=true;state.universeView.x+=dx;state.universeView.y+=dy;state.universePan.last=point;applyUniverseTransform();});
$("#file-universe").addEventListener("pointerup",event=>{if(!state.universePan||state.universePan.pointerId!==event.pointerId)return;state.universePan=null;event.currentTarget.classList.remove("panning");event.currentTarget.releasePointerCapture(event.pointerId);window.setTimeout(()=>{state.universeDidPan=false;},0);});
$("#file-universe").addEventListener("pointercancel",event=>{state.universePan=null;event.currentTarget.classList.remove("panning");});
$("#file-universe").addEventListener("click",event=>{if(state.universeDidPan)return;const node=event.target.closest("[data-universe-file]");if(!node)return;const file=state.files.find(item=>item.relativePath===node.dataset.universeFile);if(!file)return;state.universeSelection=file.relativePath;document.querySelectorAll("[data-universe-file]").forEach(circle=>circle.classList.toggle("selected",circle.dataset.universeFile===file.relativePath));$("#universe-selection").innerHTML=`<span class="category-dot"></span><div><strong>${esc(file.name)}</strong><br><span>${esc(categoryTrail(file))} · Files/${esc(file.relativePath.replaceAll("\\","/"))}</span><br>${esc(file.summary)}</div><button data-universe-open="${esc(file.relativePath)}">Show in Explorer</button>`;});
$("#universe-selection").addEventListener("click",async event=>{const button=event.target.closest("[data-universe-open]");if(!button)return;const file=state.files.find(item=>item.relativePath===button.dataset.universeOpen);if(!file)return;state.folder=parentOf(file);setView("explorer");render();await selectFile(file.relativePath);});
